// TestCheckQuota tests the CheckQuota method
func TestCheckQuota(t *testing.T) {
	tests := []struct {
		name              string
		maxPerNamespace   int
		namespace         string
		currentCount      int
		expectedErr       bool
		expectedErrStr    string
	}{
		{
			name:            "quota not exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    3,
			expectedErr:     false,
		},
		{
			name:            "quota exactly at limit",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    5,
			expectedErr:     true,
			expectedErrStr:  "policy quota exceeded",
		},
		{
			name:            "quota exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    6,
			expectedErr:     true,
			expectedErrStr:  "policy quota exceeded",
		},
		{
			name:            "unlimited quota (0)",
			maxPerNamespace: 0,
			namespace:       "default",
			currentCount:    100,
			expectedErr:     false,
		},
		{
			name:            "unknown namespace",
			maxPerNamespace: 5,
			namespace:       "unknown",
			currentCount:    0,
			expectedErr:     false,
		},
	}

